  1→import { useState, useMemo } from 'react';
  2→import { useLoanData } from './hooks/useLoanData';
  3→import { useAmortization } from './hooks/useAmortization';
  4→import { useExportPdf } from './hooks/useExportPdf';
  5→import { useRecommendations } from './hooks/useRecommendations';
  6→import type { PrePayment, AmortizationResult } from './types/loan';
  7→import { calculateAmortization } from './utils/amortization';
  8→import { LoanForm } from './components/LoanForm';
  9→import { PrePaymentList } from './components/PrePaymentList';
 10→import { RateChangeList } from './components/RateChangeList';
 11→import { SummaryCards } from './components/SummaryCards';
 12→import { AmortizationTable } from './components/AmortizationTable';
 13→import { WhatIfSimulator } from './components/WhatIfSimulator';
 14→import { RecommendationPanel } from './components/RecommendationPanel';
 15→import { PdfReport } from './components/pdf/PdfReport';
 16→import { BalanceChart } from './components/charts/BalanceChart';
 17→import { PrincipalInterestChart } from './components/charts/PrincipalInterestChart';
 18→import { ComparisonChart } from './components/charts/ComparisonChart';
 19→import { CumulativeInterestChart } from './components/charts/CumulativeInterestChart';
 20→import { PaymentBreakupChart } from './components/charts/PaymentBreakupChart';
 21→import { YearlySummaryChart } from './components/charts/YearlySummaryChart';
 22→
 23→const App = () => {
 24→  const {
 25→    loan,
 26→    setLoan,
 27→    prePayments,
 28→    addPrePayment,
 29→    updatePrePayment,
 30→    removePrePayment,
 31→    rateChanges,
 32→    addRateChange,
 33→    updateRateChange,
 34→    removeRateChange,
 35→  } = useLoanData();
 36→  const { summary, error } = useAmortization(loan, prePayments, rateChanges);
 37→  const { reportRef, isGenerating, exportPdf } = useExportPdf();
 38→  const {
 39→    data: recommendations,
 40→    loading: recLoading,
 41→    error: recError,
 42→    fetchRecommendations,
 43→  } = useRecommendations(loan, prePayments, rateChanges);
 44→
 45→  const [plannedPPs, setPlannedPPs] = useState<PrePayment[]>([]);
 46→  const [activeTab, setActiveTab] = useState<'prepayments' | 'rates'>('prepayments');
 47→
 48→  const simulatedResult = useMemo<AmortizationResult | null>(() => {
 49→    if (!loan || plannedPPs.length === 0) return null;
 50→    const allPPs = [...prePayments, ...plannedPPs];
 51→    return calculateAmortization(loan, allPPs, rateChanges);
 52→  }, [loan, prePayments, rateChanges, plannedPPs]);
 53→
 54→  const activeResult = simulatedResult ?? summary?.withPrePayments ?? null;
 55→
 56→  return (
 57→    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-white to-blue-50/30">
 58→      {/* Header */}
 59→      <header className="sticky top-0 z-30 border-b border-slate-200/80 bg-white/80 backdrop-blur-lg">
 60→        <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
 61→          <div className="flex h-16 items-center justify-between">
 62→            <div className="flex items-center gap-3">
 63→              <div className="flex h-9 w-9 items-center justify-center rounded-xl bg-gradient-to-br from-blue-600 to-indigo-600 shadow-md shadow-blue-600/20">
 64→                <svg
 65→                  className="h-5 w-5 text-white"
 66→                  fill="none"
 67→                  viewBox="0 0 24 24"
 68→                  strokeWidth="2"
 69→                  stroke="currentColor"
 70→                >
 71→                  <path
 72→                    strokeLinecap="round"
 73→                    strokeLinejoin="round"
 74→                    d="M2.25 18.75a60.07 60.07 0 0115.797 2.101c.727.198 1.453-.342 1.453-1.096V18.75M3.75 4.5v.75A.75.75 0 013 6h-.75m0 0v-.375c0-.621.504-1.125 1.125-1.125H20.25M2.25 6v9m18-10.5v.75c0 .414.336.75.75.75h.75m-1.5-1.5h.375c.621 0 1.125.504 1.125 1.125v9.75c0 .621-.504 1.125-1.125 1.125h-.375m1.5-1.5H21a.75.75 0 00-.75.75v.75m0 0H3.75m0 0h-.375a1.125 1.125 0 01-1.125-1.125V15m1.5 1.5v-.75A.75.75 0 003 15h-.75M15 10.5a3 3 0 11-6 0 3 3 0 016 0zm3 0h.008v.008H18V10.5zm-12 0h.008v.008H6V10.5z"
 75→                  />
 76→                </svg>
 77→              </div>
 78→              <div>
 79→                <h1 className="text-lg font-bold text-slate-900 leading-tight">Loan Analyser</h1>
 80→                <p className="text-xs text-slate-500 hidden sm:block">
 81→                  Smart insights for your loan
 82→                </p>
 83→              </div>
 84→            </div>
 85→            <div className="flex items-center gap-3" style={{ display: 'none' }}>
 86→              {summary && loan && (
 87→                <button
 88→                  onClick={() => exportPdf()}
 89→                  disabled={isGenerating}
 90→                  className="cursor-pointer group inline-flex items-center gap-2 rounded-xl bg-slate-900 px-4 py-2 text-sm font-medium text-white shadow-sm transition-all hover:bg-slate-800 hover:shadow-md disabled:opacity-50 disabled:cursor-not-allowed"
 91→                >
 92→                  {isGenerating ? (
 93→                    <>
 94→                      <svg className="h-4 w-4 animate-spin" viewBox="0 0 24 24" fill="none">
 95→                        <circle
 96→                          className="opacity-25"
 97→                          cx="12"
 98→                          cy="12"
 99→                          r="10"
100→                          stroke="currentColor"
101→                          strokeWidth="4"
102→                        />
103→                        <path
104→                          className="opacity-75"
105→                          fill="currentColor"
106→                          d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"
107→                        />
108→                      </svg>
109→                      Generating...
110→                    </>
111→                  ) : (
112→                    <>
113→                      <svg
114→                        className="h-4 w-4 transition-transform group-hover:-translate-y-0.5"
115→                        fill="none"
116→                        stroke="currentColor"
117→                        strokeWidth="2"
118→                        viewBox="0 0 24 24"
119→                      >
120→                        <path
121→                          strokeLinecap="round"
122→                          strokeLinejoin="round"
123→                          d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5M16.5 12L12 16.5m0 0L7.5 12m4.5 4.5V3"
124→                        />
125→                      </svg>
126→                      Export PDF
127→                    </>
128→                  )}
129→                </button>
130→              )}
131→            </div>
132→          </div>
133→        </div>
134→      </header>
135→
136→      <main className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-8 space-y-8">
137→        {/* Loan Form */}
138→        <LoanForm loan={loan} onSubmit={setLoan} />
139→
140→        {error && (
141→          <div className="flex items-center gap-3 rounded-xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">
142→            <svg
143→              className="h-5 w-5 shrink-0 text-red-400"
144→              fill="none"
145→              viewBox="0 0 24 24"
146→              strokeWidth="1.5"
147→              stroke="currentColor"
148→            >
149→              <path
150→                strokeLinecap="round"
151→                strokeLinejoin="round"
152→                d="M12 9v3.75m9-.75a9 9 0 11-18 0 9 9 0 0118 0zm-9 3.75h.008v.008H12v-.008z"
153→              />
154→            </svg>
155→            {error}
156→          </div>
157→        )}
158→
159→        {/* Pre-Payments & Rate Changes — Tabbed */}
160→        {loan && (
161→          <div className="rounded-2xl border border-slate-200 bg-white shadow-sm overflow-hidden">
162→            <div className="flex border-b border-slate-200">
163→              <button
164→                onClick={() => setActiveTab('prepayments')}
165→                className={`cursor-pointer flex-1 px-6 py-3.5 text-sm font-medium transition-colors relative ${
166→                  activeTab === 'prepayments'
167→                    ? 'text-blue-600 bg-blue-50/50'
168→                    : 'text-slate-500 hover:text-slate-700 hover:bg-slate-50'
169→                }`}
170→              >
171→                Pre-Payments
172→                {prePayments.length > 0 && (
173→                  <span className="ml-2 inline-flex h-5 min-w-5 items-center justify-center rounded-full bg-blue-100 px-1.5 text-xs font-semibold text-blue-700">
174→                    {prePayments.length}
175→                  </span>
176→                )}
177→                {activeTab === 'prepayments' && (
178→                  <span className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-600" />
179→                )}
180→              </button>
181→              <button
182→                onClick={() => setActiveTab('rates')}
183→                className={`cursor-pointer flex-1 px-6 py-3.5 text-sm font-medium transition-colors relative ${
184→                  activeTab === 'rates'
185→                    ? 'text-indigo-600 bg-indigo-50/50'
186→                    : 'text-slate-500 hover:text-slate-700 hover:bg-slate-50'
187→                }`}
188→              >
189→                Rate Changes
190→                {rateChanges.length > 0 && (
191→                  <span className="ml-2 inline-flex h-5 min-w-5 items-center justify-center rounded-full bg-indigo-100 px-1.5 text-xs font-semibold text-indigo-700">
192→                    {rateChanges.length}
193→                  </span>
194→                )}
195→                {activeTab === 'rates' && (
196→                  <span className="absolute bottom-0 left-0 right-0 h-0.5 bg-indigo-600" />
197→                )}
198→              </button>
199→            </div>
200→            <div className="p-6">
201→              {activeTab === 'prepayments' ? (
202→                <PrePaymentList
203→                  prePayments={prePayments}
204→                  onAdd={addPrePayment}
205→                  onUpdate={updatePrePayment}
206→                  onRemove={removePrePayment}
207→                />
208→              ) : (
209→                <RateChangeList
210→                  rateChanges={rateChanges}
211→                  onAdd={addRateChange}
212→                  onUpdate={updateRateChange}
213→                  onRemove={removeRateChange}
214→                />
215→              )}
216→            </div>
217→          </div>
218→        )}
219→
220→        {summary && loan && (
221→          <>
222→            {/* Summary Cards */}
223→            <SummaryCards summary={summary} loan={loan} />
224→
225→            {/* Recommendations */}
226→            <RecommendationPanel
227→              data={recommendations}
228→              loading={recLoading}
229→              error={recError}
230→              onFetch={fetchRecommendations}
231→            />
232→
233→            {/* What-If Simulator */}
234→            <WhatIfSimulator
235→              plannedPPs={plannedPPs}
236→              onAdd={(pp) => setPlannedPPs((prev) => [...prev, pp])}
237→              onRemove={(id) => setPlannedPPs((prev) => prev.filter((p) => p.id !== id))}
238→              currentResult={summary.withPrePayments}
239→              simulatedResult={simulatedResult}
240→            />
241→
242→            {/* Simulation Banner */}
243→            {simulatedResult && (
244→              <div className="flex items-center gap-3 rounded-xl border border-amber-200 bg-gradient-to-r from-amber-50 to-orange-50 px-5 py-3 text-sm">
245→                <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-lg bg-amber-100">
246→                  <svg
247→                    className="h-4 w-4 text-amber-600"
248→                    fill="none"
249→                    viewBox="0 0 24 24"
250→                    strokeWidth="2"
251→                    stroke="currentColor"
252→                  >
253→                    <path
254→                      strokeLinecap="round"
255→                      strokeLinejoin="round"
256→                      d="M9.813 15.904L9 18.75l-.813-2.846a4.5 4.5 0 00-3.09-3.09L2.25 12l2.846-.813a4.5 4.5 0 003.09-3.09L9 5.25l.813 2.846a4.5 4.5 0 003.09 3.09L15.75 12l-2.846.813a4.5 4.5 0 00-3.09 3.09zM18.259 8.715L18 9.75l-.259-1.035a3.375 3.375 0 00-2.455-2.456L14.25 6l1.036-.259a3.375 3.375 0 002.455-2.456L18 2.25l.259 1.035a3.375 3.375 0 002.455 2.456L21.75 6l-1.036.259a3.375 3.375 0 00-2.455 2.456z"
257→                    />
258→                  </svg>
259→                </div>
260→                <div className="flex-1">
261→                  <span className="font-semibold text-amber-800">Simulation active</span>
262→                  <span className="text-amber-700">
263→                    {' '}
264→                    — Charts and table reflect your planned pre-payments
265→                  </span>
266→                </div>
267→                <button
268→                  onClick={() => setPlannedPPs([])}
269→                  className="cursor-pointer shrink-0 rounded-lg border border-amber-300 bg-white px-3 py-1.5 text-xs font-medium text-amber-700 transition-colors hover:bg-amber-50"
270→                >
271→                  Clear
272→                </button>
273→              </div>
274→            )}
275→
276→            {/* Charts */}
277→            <div className="grid grid-cols-1 gap-6 lg:grid-cols-2">
278→              <BalanceChart summary={summary} simulatedResult={simulatedResult} />
279→              <CumulativeInterestChart summary={summary} simulatedResult={simulatedResult} />
280→            </div>
281→
282→            <div className="grid grid-cols-1 gap-6 lg:grid-cols-2">
283→              <ComparisonChart summary={summary} simulatedResult={simulatedResult} />
284→              <PaymentBreakupChart summary={summary} />
285→            </div>
286→
287→            <PrincipalInterestChart
288→              schedule={activeResult!.schedule}
289→              isSimulated={!!simulatedResult}
290→            />
291→
292→            <YearlySummaryChart schedule={activeResult!.schedule} isSimulated={!!simulatedResult} />
293→
294→            {/* Amortization Table */}
295→            <AmortizationTable
296→              schedule={activeResult!.schedule}
297→              isSimulated={!!simulatedResult}
298→              actualScheduleLength={summary.withPrePayments.schedule.length}
299→              plannedPPMonths={new Set(plannedPPs.map((pp) => pp.date.substring(0, 7)))}
300→            />
301→          </>
302→        )}
303→      </main>
304→
305→      {/* Footer */}
306→      <footer className="border-t border-slate-200 bg-white mt-16">
307→        <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-6 text-center text-xs text-slate-400">
308→          Loan Analyser — All calculations are approximate and for informational purposes only
309→        </div>
310→      </footer>
311→
312→      {isGenerating && summary && loan && activeResult && (
313→        <PdfReport
314→          ref={reportRef}
315→          loan={loan}
316→          summary={summary}
317→          prePayments={prePayments}
318→          rateChanges={rateChanges}
319→          activeResult={activeResult}
320→          isSimulated={!!simulatedResult}
321→        />
322→      )}
323→    </div>
324→  );
325→};
