  1→import { useMemo } from 'react';
  2→import {
  3→  AreaChart,
  4→  Area,
  5→  XAxis,
  6→  YAxis,
  7→  CartesianGrid,
  8→  Tooltip,
  9→  Legend,
 10→  ResponsiveContainer,
 11→} from 'recharts';
 12→import type { LoanSummary, AmortizationResult } from '../../types/loan';
 13→import { formatCurrency, formatDate } from '../../utils/formatters';
 14→
 15→interface Props {
 16→  summary: LoanSummary;
 17→  simulatedResult?: AmortizationResult | null;
 18→}
 19→
 20→const buildCumulativeData = (summary: LoanSummary, simulatedResult?: AmortizationResult | null) => {
 21→  const { withPrePayments, withoutPrePayments } = summary;
 22→
 23→  const maxLen = Math.max(
 24→    withPrePayments.schedule.length,
 25→    withoutPrePayments.schedule.length,
 26→    simulatedResult?.schedule.length ?? 0,
 27→  );
 28→
 29→  let cumOriginal = 0;
 30→  let cumActual = 0;
 31→  let cumSimulated = 0;
 32→
 33→  return Array.from({ length: maxLen }, (_, i) => {
 34→    const dateStr =
 35→      withoutPrePayments.schedule[i]?.date ??
 36→      withPrePayments.schedule[i]?.date ??
 37→      simulatedResult?.schedule[i]?.date ??
 38→      '';
 39→
 40→    cumOriginal += withoutPrePayments.schedule[i]?.interestComponent ?? 0;
 41→    cumActual += withPrePayments.schedule[i]?.interestComponent ?? 0;
 42→    if (simulatedResult) {
 43→      cumSimulated += simulatedResult.schedule[i]?.interestComponent ?? 0;
 44→    }
 45→
 46→    const entry: Record<string, number | string> = {
 47→      month: i + 1,
 48→      label: dateStr ? formatDate(dateStr) : '',
 49→      original: Math.round(cumOriginal),
 50→      actual: Math.round(cumActual),
 51→    };
 52→    if (simulatedResult) {
 53→      entry.simulated = Math.round(cumSimulated);
 54→    }
 55→    return entry;
 56→  });
 57→};
 58→
 59→export const CumulativeInterestChart = ({ summary, simulatedResult }: Props) => {
 60→  const data = useMemo(
 61→    () => buildCumulativeData(summary, simulatedResult),
 62→    [summary, simulatedResult],
 63→  );
 64→
 65→  return (
 66→    <div className="rounded-2xl border border-slate-200 bg-white p-6 shadow-sm">
 67→      <h3 className="mb-4 text-lg font-bold text-slate-900">Cumulative Interest Paid</h3>
 68→      <ResponsiveContainer width="100%" height={350}>
 69→        <AreaChart data={data}>
 70→          <defs>
 71→            <linearGradient id="gradOriginal" x1="0" y1="0" x2="0" y2="1">
 72→              <stop offset="5%" stopColor="#94a3b8" stopOpacity={0.3} />
 73→              <stop offset="95%" stopColor="#94a3b8" stopOpacity={0} />
 74→            </linearGradient>
 75→            <linearGradient id="gradActual" x1="0" y1="0" x2="0" y2="1">
 76→              <stop offset="5%" stopColor="#ef4444" stopOpacity={0.3} />
 77→              <stop offset="95%" stopColor="#ef4444" stopOpacity={0} />
 78→            </linearGradient>
 79→            <linearGradient id="gradSimulated" x1="0" y1="0" x2="0" y2="1">
 80→              <stop offset="5%" stopColor="#f59e0b" stopOpacity={0.3} />
 81→              <stop offset="95%" stopColor="#f59e0b" stopOpacity={0} />
 82→            </linearGradient>
 83→          </defs>
 84→          <CartesianGrid strokeDasharray="3 3" />
 85→          <XAxis dataKey="month" label={{ value: 'Month', position: 'insideBottom', offset: -5 }} />
 86→          <YAxis tickFormatter={(v) => formatCurrency(v)} width={100} />
 87→          <Tooltip
 88→            formatter={(value) => formatCurrency(Number(value))}
 89→            labelFormatter={(_: unknown, payload: readonly { payload?: { label?: string } }[]) =>
 90→              payload?.[0]?.payload?.label || ''
 91→            }
 92→          />
 93→          <Legend />
 94→          <Area
 95→            type="monotone"
 96→            dataKey="original"
 97→            name="Original Schedule"
 98→            stroke="#94a3b8"
 99→            fill="url(#gradOriginal)"
100→            strokeWidth={2}
101→          />
102→          <Area
103→            type="monotone"
104→            dataKey="actual"
105→            name="Actual (with adjustments)"
106→            stroke="#ef4444"
107→            fill="url(#gradActual)"
108→            strokeWidth={2}
109→          />
110→          {simulatedResult && (
111→            <Area
112→              type="monotone"
113→              dataKey="simulated"
114→              name="Simulated (what-if)"
115→              stroke="#f59e0b"
116→              fill="url(#gradSimulated)"
117→              strokeWidth={2}
118→              strokeDasharray="6 3"
119→            />
120→          )}
121→        </AreaChart>
122→      </ResponsiveContainer>
123→    </div>
124→  );
125→};
